     1→import 'server-only';
     2→import { SignJWT, jwtVerify } from 'jose';
     3→
     4→// JWT issuer and audience configuration
     5→const JWT_ISSUER = process.env.JWT_ISSUER || 'wmg2027-chatbot';
     6→const JWT_AUDIENCE = process.env.JWT_AUDIENCE || 'wmg2027-admin';
     7→
     8→/**
     9→ * Get and validate JWT secret from environment
    10→ * @throws Error if SESSION_SECRET is not set or too short
    11→ */
    12→function getJwtSecret(): Uint8Array {
    13→  const sessionSecret = process.env.SESSION_SECRET;
    14→
    15→  // Validate SESSION_SECRET is set in production
    16→  if (!sessionSecret && process.env.NODE_ENV === 'production') {
    17→    throw new Error('SESSION_SECRET environment variable is required in production');
    18→  }
    19→
    20→  // Use fallback only in development/test
    21→  const secret = sessionSecret || 'wmg2027-session-secret-key-32chars';
    22→
    23→  // Validate minimum length (32 chars for HS256)
    24→  if (secret.length < 32) {
    25→    throw new Error('SESSION_SECRET must be at least 32 characters');
    26→  }
    27→
    28→  return new TextEncoder().encode(secret);
    29→}
    30→
    31→/**
    32→ * JWT トークンを生成
    33→ * @returns JWT トークン文字列
    34→ */
    35→export async function createToken(): Promise<string> {
    36→  const secret = getJwtSecret();
    37→
    38→  // JWT_EXPIRES_IN: 秒数（例: "3600"）または時間文字列（例: "1h"）をサポート
    39→  const expiresIn = process.env.JWT_EXPIRES_IN || '1h';
    40→
    41→  // 数値のみの場合は秒数として扱い、相対時間形式に変換
    42→  const expirationTime = /^\d+$/.test(expiresIn) ? `${expiresIn} seconds` : expiresIn;
    43→
    44→  return new SignJWT({ authenticated: true })
    45→    .setProtectedHeader({ alg: 'HS256' })
    46→    .setIssuer(JWT_ISSUER)
    47→    .setAudience(JWT_AUDIENCE)
    48→    .setExpirationTime(expirationTime)
    49→    .setIssuedAt()
    50→    .sign(secret);
    51→}
    52→
    53→/**
    54→ * JWT トークンを検証
    55→ * @param token - JWT トークン文字列
    56→ * @returns ペイロード（検証成功時）または null（検証失敗時）
    57→ */
    58→export async function verifyToken(token: string) {
    59→  try {
    60→    const secret = getJwtSecret();
    61→    const { payload } = await jwtVerify(token, secret, {
    62→      issuer: JWT_ISSUER,
    63→      audience: JWT_AUDIENCE,
    64→    });
    65→    return payload;
    66→  } catch {
    67→    return null;
    68→  }
    69→}
