/**
 * Structured Logger
 * 構造化ログ出力ユーティリティ
 *
 * Pino-based structured logging for server-side operations.
 * Provides consistent log formatting with timestamp, level, request ID, and context.
 *
 * Features:
 * - JSON structured output in production
 * - Pretty print in development
 * - Request ID tracking for request correlation
 * - Context-aware child loggers
 * - Log levels: debug, info, warn, error
 */

import pino from 'pino';

/**
 * Logger configuration based on environment
 */
const isDevelopment = process.env.NODE_ENV !== 'production';

/**
 * Service metadata for log context
 */
const serviceContext = {
  service: 'wmg2027-chatbot',
  version: process.env.npm_package_version || '0.1.0',
  environment: process.env.NODE_ENV || 'development',
};

/**
 * Create pino logger instance with structured output
 */
export const logger = pino({
  level: process.env.LOG_LEVEL || (isDevelopment ? 'debug' : 'info'),
  formatters: {
    level: label => {
      return { level: label.toUpperCase() };
    },
    bindings: () => {
      // Include service context in all log messages
      return serviceContext;
    },
  },
  timestamp: pino.stdTimeFunctions.isoTime,
  // Add request ID mixin when available
  mixin: () => {
    return {};
  },
  // Pretty print in development for better readability
  ...(isDevelopment && {
    transport: {
      target: 'pino-pretty',
      options: {
        colorize: true,
        translateTime: 'SYS:standard',
        ignore: 'pid,hostname',
      },
    },
  }),
});

/**
 * Generate a unique request ID
 */
export function generateRequestId(): string {
  return `req_${Date.now().toString(36)}_${Math.random().toString(36).substring(2, 11)}`;
}

/**
 * Request context interface
 */
export interface RequestContext {
  requestId: string;
  method?: string;
  path?: string;
  userAgent?: string;
  ip?: string;
  [key: string]: unknown;
}

/**
 * Create a child logger with specific context
 * @param context - Context object to be included in all log messages
 * @returns Child logger instance
 */
export function createLogger(context: Record<string, unknown>) {
  return logger.child(context);
}

/**
 * Create a request-scoped logger with request ID and metadata
 * @param requestId - Unique request identifier
 * @param context - Additional context for the request
 * @returns Child logger with request context
 */
export function createRequestLogger(requestId: string, context?: Partial<RequestContext>) {
  return logger.child({
    requestId,
    ...context,
  });
}

/**
 * Get or create a request ID from headers
 * Uses x-request-id header if present, otherwise generates a new one
 * Note: This function uses dynamic import to avoid bundling issues
 */
export async function getRequestId(): Promise<string> {
  try {
    const { headers } = await import('next/headers');
    const headersList = await headers();
    const existingId = headersList.get('x-request-id');
    return existingId || generateRequestId();
  } catch {
    // headers() may fail outside of request context
    return generateRequestId();
  }
}

/**
 * Create a logger for the current request context
 * Automatically extracts request ID and common headers
 * Note: This function uses dynamic import to avoid bundling issues
 */
export async function createRequestContextLogger(): Promise<pino.Logger> {
  try {
    const { headers } = await import('next/headers');
    const headersList = await headers();
    const requestId = headersList.get('x-request-id') || generateRequestId();
    const userAgent = headersList.get('user-agent') || undefined;
    const forwardedFor = headersList.get('x-forwarded-for');
    const realIp = headersList.get('x-real-ip');
    const ip = forwardedFor?.split(',')[0]?.trim() || realIp || undefined;

    return logger.child({
      requestId,
      userAgent,
      ip,
    });
  } catch {
    // Fall back to base logger outside of request context
    return logger.child({ requestId: generateRequestId() });
  }
}

/**
 * Log levels enum for type-safe level selection
 */
export enum LogLevel {
  DEBUG = 'debug',
  INFO = 'info',
  WARN = 'warn',
  ERROR = 'error',
}

/**
 * Structured log entry interface
 */
export interface LogEntry {
  level: LogLevel;
  message: string;
  timestamp?: string;
  requestId?: string;
  context?: Record<string, unknown>;
  error?: {
    name: string;
    message: string;
    stack?: string;
  };
}

/**
 * Format an error object for logging
 */
export function formatError(error: unknown): LogEntry['error'] {
  if (error instanceof Error) {
    return {
      name: error.name,
      message: error.message,
      stack: error.stack,
    };
  }
  return {
    name: 'UnknownError',
    message: String(error),
  };
}

/**
 * Client-side logger for browser environments
 * Falls back to console.* methods with structured output
 */
export const clientLogger = {
  info: (message: string, data?: Record<string, unknown>) => {
    if (typeof window !== 'undefined') {
      const logEntry = {
        level: 'INFO',
        message,
        timestamp: new Date().toISOString(),
        ...data,
      };
      if (isDevelopment) {
        console.log(`[INFO] ${message}`, data || '');
      } else {
        console.log(JSON.stringify(logEntry));
      }
    }
  },
  warn: (message: string, data?: Record<string, unknown>) => {
    if (typeof window !== 'undefined') {
      const logEntry = {
        level: 'WARN',
        message,
        timestamp: new Date().toISOString(),
        ...data,
      };
      if (isDevelopment) {
        console.warn(`[WARN] ${message}`, data || '');
      } else {
        console.warn(JSON.stringify(logEntry));
      }
    }
  },
  error: (message: string, error?: unknown) => {
    if (typeof window !== 'undefined') {
      const logEntry = {
        level: 'ERROR',
        message,
        timestamp: new Date().toISOString(),
        error: error ? formatError(error) : undefined,
      };
      if (isDevelopment) {
        console.error(`[ERROR] ${message}`, error || '');
      } else {
        console.error(JSON.stringify(logEntry));
      }
    }
  },
  debug: (message: string, data?: Record<string, unknown>) => {
    if (typeof window !== 'undefined' && isDevelopment) {
      console.debug(`[DEBUG] ${message}`, data || '');
    }
  },
};

